pipeline.evaluate:
(() => {
  const pre = document.querySelector('pre');
  if (!pre) return [];
  const data = JSON.parse(pre.textContent);
  const results = [];
  for (let i = 0; i < data[1].length; i++) {
    results.push({
      title: data[1][i],
      description: data[2][i],
      url: data[3][i]
    });
  }
  return results;
})()
